$repos = Get-ChildItem D:\repos\dflow -Directory | Where-Object { Test-Path "$($_.FullName)\.git" }
foreach ($r in $repos) {
  Write-Output "=== $($r.Name) ==="
  git -C $r.FullName branch --show-current
  $st = git -C $r.FullName status --porcelain
  if ($st) { Write-Output "DIRTY ($(@($st).Count) changes)" } else { Write-Output "clean" }
}

$repos = Get-ChildItem D:\repos\dflow -Directory | Where-Object { Test-Path "$($_.FullName)\.git" }
foreach ($r in $repos) {
  Write-Output "================ $($r.Name) ================"
  git -C $r.FullName fetch --all --prune 2>&1 | Out-String | Write-Output
  git -C $r.FullName pull --ff-only 2>&1 | Out-String | Write-Output
}

$f = "C:\Users\ahazan2\.claude\projects\D--repos-dflow\e050f34c-5592-41a7-94b2-de0cbb3a0c02\tool-results\be858orcd.txt"
$lines = Get-Content $f
$name=""
foreach ($l in $lines) {
  if ($l -match '=+ (.+?) =+') { $name = $matches[1] }
  elseif ($l -match 'sandbox-albert\s+->\s+origin/sandbox-albert') { Write-Output "$name : $($l.Trim())" }
  elseif ($l -match 'Already up to date') { Write-Output "$name : already up to date" }
  elseif ($l -match '^\s*Fast-forward') { Write-Output "  (fast-forwarded sandbox-albert)" }
  elseif ($l -match '(\d+) files? changed') { Write-Output "  $($l.Trim())" }
}

