716	    function mapHeaderValues(colHeaders, groups, header) {
717	      const column = colHeaders.find(h => h?.field === header);
718	
719	      if (!column) return;
720	
721	      column.valueGetter = (m) => {
722	        if ((header === 'licensor' || header === 'property') && isSpruceNonLicItem(m?.data)) {
723	          return 'NON-LIC';
724	        }
725	
726	        // Step 1: Collect ALL merchGroups that match the header type
727	        const allMerchGroups: any[] = [];
728	        groups.forEach(g => {
729	          const mgTypeDesc = g?.mgTypeDesc?.toLowerCase().replace(/\s/g, '');
730	          if (mgTypeDesc === header && g?.merchGroups?.length) {
731	            allMerchGroups.push(...g.merchGroups);
732	          }
733	        });
734	
735	        if (!allMerchGroups.length) return null;
736	
737	        // Step 2: Find the correct group based on conditions
738	        if (m?.data?.is_item_old) {
739	          const matchedGroup = allMerchGroups.find(
740	            group =>
741	              group?.mg_code === m?.data[header] &&
742	              new Date(group?.createdTime).getFullYear() !== 2025
743	          );
744	          return matchedGroup?.mg_desc;
745	        } else {
746	          const matchedGroup = allMerchGroups.find(
747	            group => group?.mg_id === m?.data[`${header}_id`]
748	          );
749	          return matchedGroup?.mg_desc;
750	        }
751	      };
752	    }
