1150	
1151	    function monthToComparableNumber(date) {
1152	
1153	      if (date === undefined || date === null || date.length !== 10) {
1154	        return date.length;
1155	      }
1156	      var yearNumber = date.substring(6, 10);
1157	      var dayNumber = date.substring(3, 5);
1158	      var monthNumber = date.substring(0, 2);
1159	      var result = yearNumber * 10000 + monthNumber * 100 + dayNumber;
1160	      return result;
1161	    }
1162	
1163	
1164	    date1 = formatDate(date1)
1165	
1166	    date2 = formatDate(date2)
1167	
1168	    var date1Number = monthToComparableNumber(date1);
1169	    var date2Number = monthToComparableNumber(date2);
1170	    if (date1Number === null && date2Number === null) {
1171	      return 0;
1172	    }
1173	    if (date1Number === null) {
1174	      return -1;
1175	    }
1176	    if (date2Number === null) {
1177	      return 1;
1178	    }
1179	    return date1Number - date2Number;
