  constructor(
    public ItemLibraryService: ItemLibraryService,
    public itemService: itemService,
    public dialog: MatDialog,
    private metaService: Meta,
    private router: Router,
    private _snackBar: MatSnackBar,
    private ItemDetailService: ItemDetailService,
    private gridUISetupService: GridUISetupService,
    private configService: ConfigService,
    private loaderService: LoaderService,
    private agGridCellNotesService: AgGridCellNotesService,
    private helperService: HelperService,
    private ngZone: NgZone,
    private cdr: ChangeDetectorRef) {
    console.log('[[DEBUG]] ItemLibraryComponent Constructor START');


    let url = this.router.url;
    let urlArray = url.split('/');
    this.currentUrl = urlArray[urlArray.length - 1];
    window['togglePageToolbar'] = this.toggleToolbarVisibility.bind(this);

    this.getRowNodeId = function (data) {
      return data.data['id'];
    };

    // Register all custom framework components (clean + alphabetical)
    this.frameworkComponents = {
      autoCompelete: AutocompleteComponent,
      customDropdown: customDropdownComponent,
      customTooltip: CustomTooltipComponent,
      customTotalCount: CustomTotalCountComponent,
      datePicker: rfqDatepickerComponent,
      imageEditor: imageComponent,
      itemThumbnail: ItemThumbnailComponent,
      numericCellEditor: NumericEditor,
      propertyCell: PropertyCellComponent,
      statusPill: StatusPillComponent,
    };

    // Set default column definitions FIRST
    this.defaultColDef = {
      resizable: true,
      sortable: true,
      filter: 'agTextColumnFilter',
      floatingFilter: true,
      editable: true,
      pivot: false,
      wrapHeaderText: true,
      autoHeaderHeight: true,
      onCellDoubleClicked: this.navigateToItemDetail
    };

    this.sideBar = GRID_SIDEBAR_CONFIG;

    this.itemLibraryCellNotes = this.agGridCellNotesService.createDataSource(
      'item_library',
      getCurrentUserDisplayName,
    );

    // NOW set grid options with the defined defaultColDef
    this.gridOptions = {
      rowModelType: 'serverSide',
      popupParent: document.body,
      defaultColDef: this.defaultColDef, // This is now defined
      detailRowAutoHeight: false,
      cellSelection: true,
      pagination: true,
      paginationPageSize: 100,
      paginationPageSizeSelector: [100, 200, 500, 1000],
      cacheBlockSize: 100,
      maxBlocksInCache: 10,
      blockLoadDebounceMillis: 500,
      animateRows: true,
      loading: true,
      suppressLoadingOverlay: true,
      tooltipShowDelay: 100,
      tooltipShowMode: "whenTruncated",
      components: this.frameworkComponents,
      detailCellRenderer: this.customDetailCellRenderer,
      getRowHeight: this.getRowHeight,
      sideBar: this.sideBar,
      enableFilterHandlers: true,
      getRowId: (params: GetRowIdParams) => String(params.data.id),
      ...this.itemLibraryCellNotes.gridOptions,
      context: {
        router: this.router,
        dialog: this.dialog,
        snackBar: this._snackBar,
        itemService: this.itemService,
        itemLibraryService: this.ItemLibraryService,
        itemDetailService: this.ItemDetailService,
        createRfqDraftFromLibraryItem: this.createRfqDraftFromLibraryItem.bind(this),
        togglePageToolbar: this.toggleToolbarVisibility.bind(this),
        currentUrl: this.currentUrl,
        phases: {
          pop: null,
          licensor: null
        },
        role: this.role,
        loaderService: this.loaderService,
        onItemThumbnailMouseEnter: (data: any, node: RowNode) => this.showThumbnailPreview(data, node),
        onItemThumbnailMouseLeave: () => this.hideThumbnailPreview()
      },
      statusBar: {
        statusPanels: [
          { statusPanel: 'agTotalRowCountComponent', align: 'center' },
          { statusPanel: 'agFilteredRowCountComponent' },
          { statusPanel: 'agSelectedRowCountComponent' },
          { statusPanel: 'agAggregationComponent' }
        ]
      },
      onRowClicked: (event) => {
        if (this.layout === 'split' && event.data) {
          this.activeItem = event.data;
          this.activeItemImgSrc = event.data.pic?.Thumbnail
            ? this.helperService.buildPublicUrl(event.data.pic.Thumbnail)
            : event.data.pic?.FullSizePicture
            ? this.helperService.buildPublicUrl(event.data.pic.FullSizePicture)
            : null;
        }
      },
    };

    // Detail Cell Renderer
    this.customDetailCellRenderer = 'myDetailCellRenderer';
    console.log('[[DEBUG]] ItemLibraryComponent ngOnInit START');

    // Update viewport meta tag
    this.metaService.updateTag({ name: 'viewport', content: 'width=device-width, initial-scale=1' },'name=viewport'
    );

    const backgroundCard = getComputedStyle(document.body)
      .getPropertyValue('--background-card')
      .trim();

    this.darkMode = backgroundCard;

    if (backgroundCard === 'white') {
      this.gridClass = 'ag-theme-alpine';
    } else if (backgroundCard === '#1a202e') {
      this.gridClass = 'ag-theme-alpine-dark';
    }

    this.fillOperation = (fillOperationParams) => {
      const { column, values } = fillOperationParams;
      const targetValue = values[0];
      const colId = column.colId;

      for (let i = 0; i < this.rowData.length; i++) {
        const cell = this.rowData[i][colId];

        if (!cell) continue;

        const matches =
          cell.title === targetValue ||
          cell.RFQGroup_name === targetValue ||
          cell.data === targetValue;

        if (matches) {
          if (cell.data) {
            this.findMGfromArray(cell, this.rowData);
            return { title: cell.data };
          }
          return cell;
        }
      }

      return targetValue;
    };


    this.itemLibraryViewsInit$ = forkJoin({
      views: this.itemService.getUserGridViews({ grid_id: 'itemLibrary' }).pipe(catchError(() => of([]))),
      def: this.itemService.getGridDefaultView({ grid_id: 'itemLibrary' }).pipe(catchError(() => of(null)))
    }).pipe(
      tap(({ views, def }) => this.applyItemLibraryViewListFromApi(views, def)),
      shareReplay(1)
    );
    this.itemLibraryViewsInit$.subscribe({ error: (err) => console.error('[ItemLibraryComponent] itemLibraryViewsInit$ failed:', err) });
  }

  private applyItemLibraryViewListFromApi(views: any[], def: { view_name: string } | null): void {
    if (views && views.length) {
      this.viewLayouts = views.map((v: any) => ({
        layout_name: v.view_name,
        is_default: !!v.is_default
      }));
    } else {
      this.viewLayouts = [{ layout_name: 'Default' }];
    }
    const defaultName = def?.view_name;
    const match = defaultName && this.viewLayouts.find((v) => v.layout_name === defaultName);
    this.selectedViewLayout = match || this.viewLayouts[0];
  }

  applyTagsFilter(tags: string[]) {
    if (!this.gridApi) return;
    this.tagsQuery = (tags || []).join(' ');
    if (this.gridApi) {
      this.serverSideDatasource = this.createServerSideDatasource([]);
      this.gridApi.setGridOption("serverSideDatasource", this.serverSideDatasource);
    }
  }

  async onSaveNewView(value) {
    if (!value || !value.trim()) return;

    const viewName = value.trim();
    this.viewLayouts.push({ layout_name: viewName, is_default: false });
    this.selectedViewLayout = { layout_name: viewName, is_default: false };

    const columnState = this.gridApi.getColumnState();
    const filterModel = this.gridApi.getFilterModel();

    this.itemService.saveGridViewState({
      grid_id: 'itemLibrary',
      view_name: viewName,
      column_state: columnState,
      filter_model: filterModel
    }).subscribe(
      (data) => {
        this._snackBar.open(`View "${viewName}" was created successfully.`, 'close');
      },
      (error) => {
        this._snackBar.open(`Failed to save view. Please try again.`, 'close');
        console.error('Error saving grid view state:', error);
      }
    );
  }

  onCreateNewItem = async () => {
    let href = document.location.href.split('/')
    const itemId = href[href.length - 1]
    const dialogRef = this.dialog.open(NewItemDialogComponent, {
      panelClass: 'create-new-item-dialog',
      width: 'min(1180px, calc(100vw - 48px))',
      maxWidth: 'calc(100vw - 48px)',
      maxHeight: 'calc(100vh - 48px)',
      data: {
        itemId: itemId
      }
    })
    dialogRef.afterClosed().subscribe(async (message) => {
      if (message) {
        // ✅ This is where SSRM takes over and fetches getAllitems
        if (this.gridApi) {
          this.gridApi.setGridOption("loading", true);
          this.gridApi.setGridOption("serverSideDatasource", this.createServerSideDatasource([]));
        }
      }
    })
  }

  compareViewLayouts = (a: { layout_name: string } | null, b: { layout_name: string } | null): boolean =>
    a?.layout_name != null && b?.layout_name != null && a.layout_name === b.layout_name;

  toggleDisplayMenu(event: MouseEvent): void {
    event.stopPropagation();
    this.displayMenuOpen = !this.displayMenuOpen;
  }

  onViewChange(value) {
    this.selectedViewLayout = value;
    this.applyGridViewStateForViewName(value.layout_name);
  }

  private applyGridViewStateForViewName(layoutName: string): void {
    if (!this.gridApi || !layoutName) {
      return;
    }
    this.itemService.getGridViewState({ grid_id: 'itemLibrary', view_name: layoutName }).subscribe((res: any) => {
      if (res) {
        if (res.column_state && res.column_state.length > 0) {
          this.gridApi.applyColumnState({ state: res.column_state, applyOrder: true });
        }
        if (res.filter_model) {
          setTimeout(() => {
            this.gridApi?.setFilterModel(res.filter_model);
          }, 200);
        }
      } else {
        this.itemService
          .getSelectedGridView({ layout_name: layoutName, grid_id: 'itemLibrary' })
          .subscribe(async (legacyRes: any) => {
            if (legacyRes.length > 0) {
              this.gridApi?.applyColumnState({ state: legacyRes, applyOrder: true });
            }
          });
      }
    });
  }

  hasItemLibraryDefaultView(): boolean {
    return this.viewLayouts.some((v) => v.is_default);
  }

  onSetItemLibraryViewAsDefault(): void {
    const v = this.selectedViewLayout;
    if (!v?.layout_name || v.layout_name === 'Default') {
      return;
    }
    this.itemService.setGridDefaultView({ grid_id: 'itemLibrary', view_name: v.layout_name }).subscribe({
      next: () => {
        this.viewLayouts = this.viewLayouts.map((x) => ({
          ...x,
          is_default: x.layout_name === v.layout_name
        }));
        this.selectedViewLayout =
          this.viewLayouts.find((x) => x.layout_name === v.layout_name) ?? this.selectedViewLayout;
        this._snackBar.open('This view will load by default when you open Item Library.', 'close');
      },
      error: (err) => {
        this._snackBar.open(err?.error?.message || 'Could not set default view.', 'close');
      }
    });
  }

  onClearItemLibraryDefaultView(): void {
    this.itemService.setGridDefaultView({ grid_id: 'itemLibrary', clear: true }).subscribe({
      next: () => {
        this.viewLayouts = this.viewLayouts.map((x) => ({ ...x, is_default: false }));
        this._snackBar.open('Custom default cleared. Global Default will load on next visit.', 'close');
      },
      error: (err) => {
        this._snackBar.open(err?.error?.message || 'Could not clear default view.', 'close');
      }
    });
  }

  async onSaveLayout(selectedView) {
    if (selectedView.layout_name !== 'Default' && selectedView.layout_name != null) {
      const columnState = this.gridApi.getColumnState();
      const filterModel = this.gridApi.getFilterModel();
      this.itemService.saveGridViewState({
        grid_id: 'itemLibrary',
        view_name: selectedView.layout_name,
        column_state: columnState,
        filter_model: filterModel
      }).subscribe(
        (data) => {
          this._snackBar.open(`Current view was saved successfully.`, 'close');
        },
        (error) => {
          this._snackBar.open(`Failed to save view. Please try again.`, 'close');
          console.error('Error saving grid view state:', error);
        }
      );
    } else {
      this._snackBar.open(`You can't save on Default view. Please select a different view or create a new one.`, 'close')
    }
  }

  compareFeedbacks = (oldFeedback, newfeedback) => {
    for (let i = 0; i < oldFeedback.length; i++) {
      if (oldFeedback[i]?.status.toLowerCase() === newfeedback?.status.toLowerCase() && oldFeedback[i]?.from?.toLowerCase() === newfeedback?.from?.toLowerCase() && oldFeedback[i]?.package === newfeedback?.package) {
        newfeedback.id = oldFeedback[i].id
      }
    }
  }

  openBulkDialog(phase) {
    // Get the selected 'package' and 'from' context menu options
    const type = document.getElementsByClassName('ag-menu-option-active')[1]?.textContent;
    const from = document.getElementsByClassName('ag-menu-option-active')[3]?.textContent;

    const dialogRef = this.dialog.open(BulkUpdateComponent, {
      disableClose: true,
      width: '700px',
      data: { from: from, package: type, phase: phase.phase, status: phase.status }
    })


    dialogRef.afterClosed().subscribe(async (data) => {
      if (data) {
        const rows = this.gridApi.getSelectedRows();
        const mergedData = [];
        const ids = [];

        if (!this.merchGroups) {
          const res = await this.itemService.getMerchGroup({ divisionCode: 1, DivisionStatus: 1 }).pipe(first()).toPromise();
          this.merchGroups = res[0]?.merchGroupHeaders;
        }

        rows.forEach((row) => {
          ids.push(row.id.toString())
        })

        let newData = JSON.parse(JSON.stringify(data));
        const licenses = await <any>this.ItemDetailService.BulkGetLicensingStatus(ids).pipe(first()).toPromise()

        rows.forEach((row) => {
          if (licenses[row.id.toString()]) {
            const oldFeedback = licenses[row.id];
            // Add id field and update existing feedback if it already exists
            this.compareFeedbacks(oldFeedback, newData);
          }

          newData.itemheader_id_fk = row.id.toString()

          //Convert licensor code to full name
          if (newData?.from?.toLowerCase() !== 'pop') newData.from = this.merchGroups.find(g => g?.mgTypeDesc?.toLowerCase().replace(' ', '') === 'licensor')?.merchGroups.find(group => group?.mg_code === row?.licensor)?.mg_desc
          mergedData.push(JSON.parse(JSON.stringify(newData)))
        })


        this.ItemDetailService.BulkAddLicensingStatus(mergedData).subscribe((res: any) => {
          if (res.statusCode === 200) {
            this._snackBar.open(`Successfully bulk updated licenses!`, 'close')
          } else {
            this._snackBar.open(`An error occurred while updating licenses`, 'close')
          }
        })
      }
    })
  }

  async ngOnInit() {
    // Start loader immediately to prevent blank page flash
    this.loaderService.increment();

    setTimeout(() => this.gridApi?.setGridOption("loading", true), 100)

    try {
      const res: any = await this.itemService.verifyRole().toPromise();
      this.role = res.role
      this.gridOptions.context.role = this.role
      this.access = res.access
      if (this.role == 'vendor') {
        this.detailRowHeight = 108
      }
    } catch (err) {
      console.error('[ItemLibrary] verifyRole failed:', err);
    }

    // Collect all phases and bind action for context menu phases
    this.ItemDetailService.getLicenseFeedBacks({ from: 'POP' }).subscribe(data => {
      if (Array.isArray(data)) {
        let res = [];
        data.forEach(phase => {
          res.push({
            name: phase.phase + ' | ' + phase.status,
            action: () => this.openBulkDialog(phase)
          });
        });
        this.gridOptions.context.phases.pop = res;
      }
    });

    this.ItemDetailService.getLicenseFeedBacks({ from: 'Licensor' }).subscribe(data => {
      let res = []
      data.forEach((phase) => res.push({
        name: phase.phase + ' | ' + phase.status,
        action: () => this.openBulkDialog(phase)
      }))
      this.gridOptions.context.phases.licensor = res;
    })

    try {
      const data: any = await this.itemService.getCompanyCode().toPromise();
      this.selectedCompanyCode = data[0]['company_name']
      this.companyCode = data;
      this.divisionCode = data[0].divisionCodes
      this.selectedDivisionCode = data[0].divisionCodes
      window['selectedDivisionCode'] = data[0].divisionCodes

      if (this.selectedDivisionCode) {
          const colHeaders = [...ITEM_LIBRARY_COLUMN_HEADERS_CONFIG.columnDefs];
          const selectedDivIds = this.selectedDivisionCode.map((div: any) => div.divCode_id);
          const requests = selectedDivIds.map((divCode: number) =>
            this.itemService.getMerchGroup({ divisionCode: divCode, DivisionStatus: 1 })
          );

          forkJoin(requests).subscribe((responses: any[]) => {
            const allGroups = responses.reduce(
              (acc, resp) => acc.concat(resp[0]?.merchGroupHeaders || []),
              []
            );

            mapHeaders(colHeaders, allGroups);
            this.colHeaders = colHeaders;
            this.merchGroups = allGroups;
            window['colHeaders'] = this.colHeaders;

            for (let i = 0; i < colHeaders.length; i++) {
              const col = colHeaders[i];
              if (col.colId === 'pic') {
                col.cellRenderer = 'itemThumbnail';
                col.cellStyle = null;
                col.editable = false;
                col.sortable = false;
                col.tooltipValueGetter = () => null;
                suppressImageColumnNotes(col);
              } else {
                col.tooltipField = col.field;
                col.tooltipComponent = 'customTooltip';
              }
            }
            const fieldMap = {
              material: { field: 'Product Type', headerName: 'Product Type' },
              construction: { field: 'Product Sub-Type', headerName: 'Product Sub-Type' },
              feature: { field: 'Product Sub-Sub-Type', headerName: 'Product Sub-Sub-Type' }
            };

            const updatedColHeaders = colHeaders.map(column => {
              const mapping = fieldMap[column.field];
              return mapping ? { ...column, ...mapping } : column;
            });

            this.colHeaders = updatedColHeaders;
            this.columnDefs = updatedColHeaders;

            this.gridApi.setGridOption('columnDefs', this.columnDefs);

            if (this.gridApi) {
              this.serverSideDatasource = this.createServerSideDatasource([]);
              this.gridApi.setGridOption("serverSideDatasource", this.serverSideDatasource);
            }

            firstValueFrom(this.itemLibraryViewsInit$)
              .then(() => {
                this.applyGridViewStateForViewName(this.selectedViewLayout?.layout_name ?? 'Default');
              })
              .catch(() => {
                this.applyGridViewStateForViewName(this.selectedViewLayout?.layout_name ?? 'Default');
              });
          });
      }
    } catch (err) {
      console.error('[ItemLibrary] getCompanyCode failed:', err);
    }

    function percentFormatter(params) {
      if (params.value) {
        return formatNumber(params.value) + '%';
      }
    }

    function mapHeaders(colHeaders, groups) {
      mapHeaderValues(colHeaders, groups, 'property')
      mapHeaderValues(colHeaders, groups, 'material')
      mapHeaderValues(colHeaders, groups, 'construction')
      mapHeaderValues(colHeaders, groups, 'feature')
      mapHeaderValues(colHeaders, groups, 'size')
      mapHeaderValues(colHeaders, groups, 'licensor')
      mapHeaderValues(colHeaders, groups, 'subformat')
    }

    function mapHeaderValues(colHeaders, groups, header) {
      const column = colHeaders.find(h => h?.field === header);

      if (!column) return;

      column.valueGetter = (m) => {
        if ((header === 'licensor' || header === 'property') && isSpruceNonLicItem(m?.data)) {
          return 'NON-LIC';
        }

        // Step 1: Collect ALL merchGroups that match the header type
        const allMerchGroups: any[] = [];
        groups.forEach(g => {
          const mgTypeDesc = g?.mgTypeDesc?.toLowerCase().replace(/\s/g, '');
          if (mgTypeDesc === header && g?.merchGroups?.length) {
            allMerchGroups.push(...g.merchGroups);
          }
        });

        if (!allMerchGroups.length) return null;

        // Step 2: Find the correct group based on conditions
        if (m?.data?.is_item_old) {
          const matchedGroup = allMerchGroups.find(
            group =>
              group?.mg_code === m?.data[header] &&
              new Date(group?.createdTime).getFullYear() !== 2025
          );
          return matchedGroup?.mg_desc;
        } else {
          const matchedGroup = allMerchGroups.find(
            group => group?.mg_id === m?.data[`${header}_id`]
          );
          return matchedGroup?.mg_desc;
        }
      };
    }

    function isSpruceNonLicItem(row) {
      return Number(row?.div_code_fk) === 9;
    }

    function formatNumber(number) {
      // this puts commas into the number eg 1000 goes to 1,000,
      // i pulled this from stack overflow, i have no idea how it works
      return Number.parseFloat(number).toFixed(2).toString().replace(/(\d)(?=(\d{3})+(?!\d))/g, "$1,");
    }

    function formatDate(input) {
      if (input == null) return ''
      if (input.includes("-")) {
        var datePart = input.match(/\d+/g),
          year = datePart[0].substring(), // get only two digits
          month = datePart[1], day = datePart[2];
        return month + '/' + day + '/' + year;
      } else {
        return input
      }
    }

  }


  createServerSideDatasource(divisionCodeIds: number[]): IServerSideDatasource {
    const isArchive = this.currentUrl === 'archive';
    if (divisionCodeIds.length === 0) {
      divisionCodeIds = this.selectedDivisionCode?.map(d => d.divCode_id) || [];
    }
    return {
      getRows: (params: IServerSideGetRowsParams) => {
        const request = {
          startRow: params.request.startRow,
          endRow: params.request.endRow,
          filterModel: {
            ...(params.request.filterModel || {}),
            ...(this.tagsQuery ? { tags: { type: 'contains', filter: this.tagsQuery } } : {})
          },
          isArchive,
          divisionCodeIds
        };

        this.ItemLibraryService.getAllitems(request).subscribe({
          next: async (res: any) => {
            const rowData = res.rows || [];
            const totalCount = res.totalCount ?? rowData.length;

            this.rowData = rowData;
            this.totalRowCount = totalCount;

            // Update status panel
            const statusPanelComp = this.gridApi.getStatusPanel('customTotalCount');
            if (statusPanelComp) {
              (statusPanelComp as any).setTotalCount(totalCount);
            }

            // Always set loading to false when we have a response
            this.gridApi.setGridOption("loading", false);

            // Decrement loader for initial load or division change load
            this.decrementLoaderIfNeeded();

            // Success callback with data
            params.success({
              rowData,
              rowCount: totalCount,
            });

            mergePreloadCellNotes(this.itemLibraryCellNotes, rowData, 'id');
            this.restoreStateFromSession();
          },
          error: (error) => {
            this.gridApi.setGridOption("loading", false);
            // Decrement loader on error for initial load or division change load
            this.decrementLoaderIfNeeded();
            params.fail();
          }
        });
      }
    };
  }


