  private async createRfqDraftFromLibraryItem(row: any): Promise<void> {
    if (!row?.id) {
      this._snackBar.open('Please select an item to create an RFQ draft.', 'close', { duration: 3000 });
      return;
    }

    this.loaderService.increment();
    try {
      const itemInfo: any = await firstValueFrom(this.ItemDetailService.getItemInfo({ id: row.id }));
      if (!Array.isArray(itemInfo) || itemInfo.length === 0) {
        this._snackBar.open('Could not load the selected item details.', 'close', { duration: 4000 });
        return;
      }

      const itemData = itemInfo[0];
      const dialogRef = this.dialog.open(addNewProductComponent, {
        panelClass: 'add-new-product-dialog',
        disableClose: true,
        data: {
          details: {
            currentUrl: this.currentUrl,
            selectedDivisionCodeStatus: this.divisionCodeStatus,
            selectedDivisionCode: this.selectedDivisionCode,
          },
          selectedRow: null,
          option: null,
          duplicatedMode: false,
          highlighted: false,
          initialLibraryItemInfo: itemInfo,
          sourceLibraryItemId: itemData?.item_id_pk ?? row.id,
          sourceLibraryItemNum: itemData?.item_num_id ?? null,
        },
      });

      dialogRef.afterClosed().subscribe((result) => {
        if (result) {
          this._snackBar.open('RFQ draft created from library item.', 'close', { duration: 3000 });
        }
      });
    } catch (error) {
      console.error('[ItemLibrary] createRfqDraftFromLibraryItem failed:', error);
      this._snackBar.open('Could not create an RFQ draft from this item.', 'close', { duration: 5000 });
    } finally {
      this.loaderService.decrement();
    }
  }

