onGridReady(params) {
  this.params = params;
  this.gridApi = params.api;
  window['gridApi'] = this.gridApi;
  this.gridUISetupService.bootstrap(this.gridApi, this.destroy$);

  // Switching the Display "View" between Table and Gallery toggles the
  // @if/@else branch in the template, which destroys and recreates the
  // ag-grid-angular component. On recreation onGridReady fires again on a
  // fresh grid that has neither columns nor a datasource (those are only set
  // once during the initial getCompanyCode() flow in ngOnInit). Re-apply the
  // already-computed columnDefs and datasource so the table repopulates
  // instead of rendering an empty, never-loading grid.
  if (this.columnDefs?.length) {
    this.gridApi.setGridOption('columnDefs', this.columnDefs);
  }
  if (this.serverSideDatasource) {
    this.gridApi.setGridOption('loading', true);
    this.gridApi.setGridOption('serverSideDatasource', this.serverSideDatasource);
  }
}

