import { describe, expect, it } from '@jest/globals';
import {
  buildRailFields,
  glyphColor,
  propertyDotColor,
  propertyHue,
  railItemMeta,
  railItemName,
  resolveStatusTone,
  resolveThumbSrc,
  STATUS_KEY_MAP,
  STATUS_TONES,
  stringToHue,
  tileBorderColor,
  tileGradient,
} from './item-library-shared';

describe('stringToHue', () => {
  it('is deterministic for the same input', () => {
    expect(stringToHue('Woodland Friends')).toBe(stringToHue('Woodland Friends'));
  });

  it('always returns a hue in the 0–359 range', () => {
    for (const s of ['', 'a', 'Cosmic Cadets', 'Pixel Pups', '12345', 'a very long property name here']) {
      const hue = stringToHue(s);
      expect(hue).toBeGreaterThanOrEqual(0);
      expect(hue).toBeLessThanOrEqual(359);
      expect(Number.isInteger(hue)).toBe(true);
    }
  });

  it('returns 0 for the empty string', () => {
    expect(stringToHue('')).toBe(0);
  });

  it('produces different hues for different properties', () => {
    expect(stringToHue('Woodland Friends')).not.toBe(stringToHue('Cosmic Cadets'));
  });
});

describe('propertyHue', () => {
  it('prefers the property name', () => {
    expect(propertyHue({ property: 'Tide Pool Pals' })).toBe(stringToHue('Tide Pool Pals'));
  });

  it('falls back to property_id when property is missing', () => {
    expect(propertyHue({ property_id: 42 })).toBe(stringToHue('42'));
  });

  it('falls back to an empty string (hue 0) for null/empty items', () => {
    expect(propertyHue(null)).toBe(0);
    expect(propertyHue({})).toBe(0);
  });
});

describe('color helpers', () => {
  it('builds the tile gradient from a hue', () => {
    expect(tileGradient(128)).toBe('linear-gradient(150deg, hsl(128 46% 95%), hsl(128 40% 87%))');
  });

  it('builds the tile border color', () => {
    expect(tileBorderColor(128)).toBe('hsl(128 30% 80%)');
  });

  it('builds the glyph color', () => {
    expect(glyphColor(128)).toBe('hsl(128 42% 34%)');
  });

  it('builds the property dot color', () => {
    expect(propertyDotColor(128)).toBe('hsl(128 45% 52%)');
  });
});

describe('resolveStatusTone', () => {
  it('maps each known status label to its tone', () => {
    expect(resolveStatusTone('Concept')).toBe(STATUS_TONES['concept']);
    expect(resolveStatusTone('In Design')).toBe(STATUS_TONES['design']);
    expect(resolveStatusTone('Submitted')).toBe(STATUS_TONES['submitted']);
    expect(resolveStatusTone('Approved')).toBe(STATUS_TONES['approved']);
    expect(resolveStatusTone('In Sampling')).toBe(STATUS_TONES['sampling']);
    expect(resolveStatusTone('Production')).toBe(STATUS_TONES['production']);
    expect(resolveStatusTone('On Shelf')).toBe(STATUS_TONES['shelf']);
    expect(resolveStatusTone('Discontinued')).toBe(STATUS_TONES['discont']);
  });

  it('is case- and whitespace-insensitive', () => {
    expect(resolveStatusTone('  in DESIGN  ')).toBe(STATUS_TONES['design']);
    expect(resolveStatusTone('ON SHELF')).toBe(STATUS_TONES['shelf']);
  });

  it('falls back to the concept tone for unknown or empty status', () => {
    expect(resolveStatusTone('')).toBe(STATUS_TONES['concept']);
    expect(resolveStatusTone(null)).toBe(STATUS_TONES['concept']);
    expect(resolveStatusTone(undefined)).toBe(STATUS_TONES['concept']);
    expect(resolveStatusTone('Frozen')).toBe(STATUS_TONES['concept']);
  });

  it('keeps the tone map and key map in sync (no key points at a missing tone)', () => {
    for (const stageKey of Object.values(STATUS_KEY_MAP)) {
      expect(STATUS_TONES[stageKey]).toBeDefined();
    }
  });

  it('every tone exposes bg, fg, and dot', () => {
    for (const tone of Object.values(STATUS_TONES)) {
      expect(tone.bg).toMatch(/^#[0-9a-f]{6}$/i);
      expect(tone.fg).toMatch(/^#[0-9a-f]{6}$/i);
      expect(tone.dot).toMatch(/^#[0-9a-f]{6}$/i);
    }
  });
});

describe('resolveThumbSrc', () => {
  it('prefers the thumbnail url', () => {
    expect(resolveThumbSrc({ pic: { Thumbnail: 't.png', FullSizePicture: 'f.png' } })).toBe('t.png');
  });

  it('falls back to the full-size picture', () => {
    expect(resolveThumbSrc({ pic: { FullSizePicture: 'f.png' } })).toBe('f.png');
  });

  it('returns null when there is no image', () => {
    expect(resolveThumbSrc({ pic: {} })).toBeNull();
    expect(resolveThumbSrc({})).toBeNull();
    expect(resolveThumbSrc(null)).toBeNull();
  });
});

describe('buildRailFields', () => {
  const item = {
    itemNum: 'IT-100',
    refNum: 'RF-200',
    DSN: 'DS-300',
    season: 'SS26',
    licensorName: 'Maple & Co.',
    materialName: 'Plush',
    constructionName: 'Stitched',
    featureName: 'Embroidered',
    sizeName: '16in',
    div_code_fk: 2,
  };

  it('returns the 10 rail fields in order', () => {
    const fields = buildRailFields(item);
    expect(fields.map(f => f.label)).toEqual([
      'Item Num', 'Reference #', 'Design #', 'Season', 'Licensor',
      'Product Type', 'Sub-Type', 'Feature', 'Size', 'Division',
    ]);
  });

  it('resolves *Name fields with raw-code fallback', () => {
    const fields = buildRailFields({ licensor: 'RAW-LIC', material: 'RAW-MAT' });
    const byLabel = (l: string) => fields.find(f => f.label === l)!.value;
    expect(byLabel('Licensor')).toBe('RAW-LIC');
    expect(byLabel('Product Type')).toBe('RAW-MAT');
  });

  it('uses an em dash for missing values', () => {
    const fields = buildRailFields({});
    expect(fields.every(f => f.value === '—')).toBe(true);
  });

  it('flags mono and full fields correctly', () => {
    const fields = buildRailFields(item);
    const mono = fields.filter(f => f.mono).map(f => f.label);
    expect(mono).toEqual(['Item Num', 'Reference #', 'Design #', 'Season', 'Size']);
    expect(fields.find(f => f.label === 'Licensor')!.full).toBe(true);
  });

  it('returns an empty list for a null item', () => {
    expect(buildRailFields(null)).toEqual([]);
  });
});

describe('rail header helpers', () => {
  it('railItemName prefers item_name, then name', () => {
    expect(railItemName({ item_name: 'A', name: 'B' })).toBe('A');
    expect(railItemName({ name: 'B' })).toBe('B');
    expect(railItemName(null)).toBe('');
  });

  it('railItemMeta joins property and material with a middot, skipping blanks', () => {
    expect(railItemMeta({ property: 'Woodland Friends', material: 'Plush' })).toBe('Woodland Friends · Plush');
    expect(railItemMeta({ property: 'Woodland Friends' })).toBe('Woodland Friends');
    expect(railItemMeta({})).toBe('');
  });
});

