import { describe, expect, it, jest, beforeEach, afterAll } from '@jest/globals';
import { ItemLibraryComponent } from './itemLibrary.component';

/**
 * Focused regression tests for ItemLibraryComponent.onGridReady.
 *
 * The component is large and constructor-heavy, so instead of a full TestBed we
 * invoke the method against the prototype with a minimal mock `this`. This
 * targets the gallery -> table toggle bug: switching the Display "View" toggles
 * the @if/@else branch in the template, destroying and recreating the
 * ag-grid-angular component. On recreation onGridReady must re-apply the
 * already-computed columnDefs and serverSideDatasource, otherwise the rebuilt
 * grid has no columns and no datasource and renders an empty, never-loading grid.
 */
describe('ItemLibraryComponent.onGridReady', () => {
  const originalGridApi = (window as any)['gridApi'];

  function makeCtx(overrides: Partial<any> = {}) {
    return {
      gridUISetupService: { bootstrap: jest.fn() },
      destroy$: {},
      columnDefs: [],
      serverSideDatasource: undefined,
      ...overrides,
    } as any;
  }

  function makeApi() {
    return { setGridOption: jest.fn() } as any;
  }

  beforeEach(() => {
    jest.clearAllMocks();
  });

  afterAll(() => {
    (window as any)['gridApi'] = originalGridApi;
  });

  it('stores the api and bootstraps the grid UI', () => {
    const ctx = makeCtx();
    const api = makeApi();

    ItemLibraryComponent.prototype.onGridReady.call(ctx, { api });

    expect(ctx.gridApi).toBe(api);
    expect((window as any)['gridApi']).toBe(api);
    expect(ctx.gridUISetupService.bootstrap).toHaveBeenCalledWith(api, ctx.destroy$);
  });

  it('does NOT re-apply columns/datasource on the initial ready (nothing computed yet)', () => {
    const ctx = makeCtx({ columnDefs: [], serverSideDatasource: undefined });
    const api = makeApi();

    ItemLibraryComponent.prototype.onGridReady.call(ctx, { api });

    expect(api.setGridOption).not.toHaveBeenCalled();
  });

  it('re-applies columnDefs and datasource when the grid is recreated (gallery -> table)', () => {
    const columnDefs = [{ field: 'item_name' }];
    const serverSideDatasource = { getRows: jest.fn() };
    const ctx = makeCtx({ columnDefs, serverSideDatasource });
    const api = makeApi();

    ItemLibraryComponent.prototype.onGridReady.call(ctx, { api });

    expect(api.setGridOption).toHaveBeenCalledWith('columnDefs', columnDefs);
    expect(api.setGridOption).toHaveBeenCalledWith('loading', true);
    expect(api.setGridOption).toHaveBeenCalledWith('serverSideDatasource', serverSideDatasource);
  });

  it('re-applies columnDefs even when no datasource exists yet', () => {
    const columnDefs = [{ field: 'item_name' }];
    const ctx = makeCtx({ columnDefs, serverSideDatasource: undefined });
    const api = makeApi();

    ItemLibraryComponent.prototype.onGridReady.call(ctx, { api });

    expect(api.setGridOption).toHaveBeenCalledWith('columnDefs', columnDefs);
    expect(api.setGridOption).not.toHaveBeenCalledWith('serverSideDatasource', expect.anything());
  });
});

